// filename: n8n-code-chunk-text.js
/**
 * Podział tekstu na chunki o maksymalnej długości znaków z preferencją końców zdań.
 *
 * Wejście (n8n Code node):
 * - Tekst: $('Redaktor').item.json.output.zredagowana_notatka
 * - Opcjonalnie: $('Redaktor').item.json.maxLen (liczba), domyślnie 2000
 *
 * Wyjście:
 * - Tablica items: [{ json: { chunk, index, part, total, length } }, ...]
 *
 * Zasada podziału:
 * 1) Granice zdań (. ! ? ; : … — -) z opcjonalnym cudzysłowem/nawiasem po znaku.
 * 2) Fallback: ostatnia spacja w oknie.
 * 3) Ostatecznie: twarde cięcie na limicie.
 *
 * Edge cases:
 * - Bardzo długie słowa > maxLen będą cięte twardo.
 * - Nadmiarowe białe znaki są redukowane dla stabilnego cięcia.
 */

function chunkTextSmart(text, maxLen = 2000) {
  if (typeof text !== 'string') return [];
  if (!text.trim()) return [];

  // Normalizacja białych znaków dla stabilnego podziału
  const normalized = text
    .replace(/\r\n/g, '\n')           // CRLF -> LF
    .replace(/[ \t]+\n/g, '\n')       // spacje przed newline
    .replace(/\n{3,}/g, '\n\n')       // maks 2 nowe linie z rzędu
    .replace(/[ \t]{2,}/g, ' ')       // wielokrotne spacje -> pojedyncza
    .trim();

  // Granice zdań, uwzględniając możliwy cudzysłów/prawy nawias po znaku
  const endSentenceRegex = /[\.!?;:…—-](?:["'”’)\]]|\s|$)/g;

  const chunks = [];
  let start = 0;

  while (start < normalized.length) {
    const remaining = normalized.length - start;
    const limit = Math.min(maxLen, remaining);
    const windowText = normalized.slice(start, start + limit);

    // a) Najdalszy koniec zdania w oknie
    let splitIndex = -1;
    let match;
    endSentenceRegex.lastIndex = 0;
    while ((match = endSentenceRegex.exec(windowText)) !== null) {
      splitIndex = match.index + match[0].length; // tnij za dopasowaniem
    }

    // b) Jeśli brak końca zdania, tnij po ostatniej spacji
    if (splitIndex === -1) {
      const lastSpace = windowText.lastIndexOf(' ');
      if (lastSpace > 0) {
        splitIndex = lastSpace + 1; // tnij po spacji
      }
    }

    // c) Jeśli brak spacji, twarde cięcie
    if (splitIndex === -1) {
      splitIndex = limit;
    }

    let chunk = normalized.slice(start, start + splitIndex).trim();
    if (chunk.length > 0) {
      chunks.push(chunk);
    }

    // Przesuń start i omiń nadmiarowe białe znaki na początku kolejnego okna
    start += splitIndex;
    while (start < normalized.length && /\s/.test(normalized[start])) {
      start++;
    }
  }

  return chunks;
}

// Pobranie źródła z node'a "Redaktor"
const redaktorItem = $('Redaktor').item;
const srcText = String(redaktorItem?.json?.output?.zredagowana_notatka ?? '');
const maxLen = Number(redaktorItem?.json?.maxLen ?? 2000);

// Podział na chunki
const chunks = chunkTextSmart(srcText, maxLen);
const total = chunks.length;

// Zwracamy każdy chunk jako osobny item (przyjazne do "Loop Over Items")
return chunks.map((chunk, index) => ({
  json: {
    chunk,
    index,           // 0-based
    part: index + 1, // 1-based
    total,
    length: chunk.length,
  },
}));
